class DeviceController:
    def __init__(self, pin_no=2):
        self.pin = machine.Pin(pin_no, machine.Pin.OUT)
        self.state = 0
        self.pin.value(self.state)

    def turn_on(self):
        self.state = 1
        self.pin.value(1)

    def turn_off(self):
        self.state = 0
        self.pin.value(0)

    def toggle(self):
        self.state = 0 if self.state else 1
        self.pin.value(self.state)

    def status(self):
        return {"device": "esp32", "state": "on" if self.state else "off"}


device = DeviceController(2)


def handle_command(message, client):
    action = message.get("action", "")
    if action == "turn_on":
        device.turn_on()
        return {"ok": True, "action": action, "status": device.status()}
    elif action == "turn_off":
        device.turn_off()
        return {"ok": True, "action": action, "status": device.status()}
    elif action == "toggle":
        device.toggle()
        return {"ok": True, "action": action, "status": device.status()}
    elif action == "status":
        return {"ok": True, "action": action, "status": device.status()}
    else:
        return {"ok": False, "error": "unknown_action", "received": message}


def connect_wifi(ssid, password, timeout=15):
    sta = network.WLAN(network.STA_IF)
    sta.active(True)
    if not sta.isconnected():
        sta.connect(ssid, password)
        start = utime.time()
        while not sta.isconnected():
            if utime.time() - start > timeout:
                raise OSError("WiFi connection timeout")
            utime.sleep_ms(200)
    return sta.ifconfig()


def start_server(ssid=None, password=None, host="0.0.0.0", port=80):
    if ssid and password:
        ipcfg = connect_wifi(ssid, password)
        print("WiFi connected:", ipcfg)
    else:
        sta = network.WLAN(network.STA_IF)
        if sta.active() and sta.isconnected():
            print("WiFi connected:", sta.ifconfig())
        else:
            print("WiFi not configured")

    server = WebSocketServer(host=host, port=port, command_handler=handle_command)
    server.start()
    print("WebSocket server running on port", port)
    print("Open http://<esp32-ip>/ in browser")
    try:
        while True:
            server.poll()
            utime.sleep_ms(10)
    finally:
        server.stop()


